mapper.select:
SELECT f.*
FROM t_fleet f
WHERE f.deleted_flag = #{queryForm.deletedFlag}

    and f.enterprise_id = #{queryForm.enterpriseId}


    AND (INSTR(f.fleet_name,#{queryForm.keyWords})
    or INSTR(f.captain_name,#{queryForm.keyWords})
    or INSTR(f.captain_phone,#{queryForm.keyWords})
    or INSTR(f.create_user_name ,#{queryForm.keyWords})
    )


    AND (INSTR(f.province,#{queryForm.registerAreaCode})
    or INSTR(f.city,#{queryForm.registerAreaCode})
    or INSTR(f.district ,#{queryForm.registerAreaCode})
    )


    AND f.audit_status = #{queryForm.auditStatus}


    and DATE_FORMAT(f.create_time, '%Y-%m-%d') >= #{queryForm.createStartTime}


    and DATE_FORMAT(f.create_time, '%Y-%m-%d') <= #{queryForm.createEndTime}



    ORDER BY f.create_time DESC

